import{_ as t,o as a,c as e,a9 as o}from"./chunks/framework.D4xYp1Zt.js";const p="/images/what-does-quadrillion-sour-patch-kids/1.jpg",s="/images/what-does-quadrillion-sour-patch-kids/2.jpg",i="/images/what-does-quadrillion-sour-patch-kids/3.jpg",l="/images/what-does-quadrillion-sour-patch-kids/5.jpg",n="/images/what-does-quadrillion-sour-patch-kids/6.jpg",h="/images/what-does-quadrillion-sour-patch-kids/7.jpg",A="/images/what-does-quadrillion-sour-patch-kids/10.jpg",g="/images/what-does-quadrillion-sour-patch-kids/11.jpg",d="/images/what-does-quadrillion-sour-patch-kids/100.png",c="/images/what-does-quadrillion-sour-patch-kids/1k.png",m="/images/what-does-quadrillion-sour-patch-kids/1m.png",u="/images/what-does-quadrillion-sour-patch-kids/1b.png",k="/images/what-does-quadrillion-sour-patch-kids/1t.png",_="/images/what-does-quadrillion-sour-patch-kids/1qd.png",b="/images/what-does-quadrillion-sour-patch-kids/1qnt.png",f="/images/what-does-quadrillion-sour-patch-kids/cover-world.png",w="/images/what-does-quadrillion-sour-patch-kids/1sx.png",q="/images/what-does-quadrillion-sour-patch-kids/1sp.png",U="/images/what-does-quadrillion-sour-patch-kids/1o.png",P="/images/what-does-quadrillion-sour-patch-kids/1n.png",x="/images/what-does-quadrillion-sour-patch-kids/pinit_fg_en_rect_gray_20.png",L=JSON.parse('{"title":"What Does a Quadrillion Sour Patch Kids Look Like?","description":"","frontmatter":{"title":"What Does a Quadrillion Sour Patch Kids Look Like?","titleZh":"一千万亿颗酸糖是什么样","date":"2013-10-03T00:00:00.000Z","originalUrl":"https://waitbutwhy.com/2013/10/what-does-quadrillion-sour-patch-kids.html","slug":"what-does-quadrillion-sour-patch-kids"},"headers":[],"relativePath":"posts/what-does-quadrillion-sour-patch-kids.md","filePath":"posts/what-does-quadrillion-sour-patch-kids.md","lastUpdated":1782886257000}'),F={name:"posts/what-does-quadrillion-sour-patch-kids.md"};function I(y,r,S,W,j,J){return a(),e("div",null,[...r[0]||(r[0]=[o('<h1 id="一千万亿颗酸糖是什么样-·-what-does-a-quadrillion-sour-patch-kids-look-like" tabindex="-1">一千万亿颗酸糖是什么样 · What Does a Quadrillion Sour Patch Kids Look Like? <a class="header-anchor" href="#一千万亿颗酸糖是什么样-·-what-does-a-quadrillion-sour-patch-kids-look-like" aria-label="Permalink to &quot;一千万亿颗酸糖是什么样 · What Does a Quadrillion Sour Patch Kids Look Like?&quot;">​</a></h1><blockquote><p>原文:<a href="https://waitbutwhy.com/2013/10/what-does-quadrillion-sour-patch-kids.html" target="_blank" rel="noreferrer">https://waitbutwhy.com/2013/10/what-does-quadrillion-sour-patch-kids.html</a> · 2013-10-03</p></blockquote><p>有些时刻很压抑。有些地方很黑暗。</p><p>然后,还有这种情况——凌晨 2 点,一个 31 岁的男人独自站在寂静公寓的厨房台面前,小心翼翼地把酸小孩软糖 (Sour Patch Kids) 一颗颗摞起来。</p><p>要理解我是怎么落到这步田地的,让我们把时间倒回几小时前的午夜——那时我正瞪着电脑屏幕,看着一篇写了一半但我讨厌的文章。</p><p>Wait But Why 上那些烂帖子的问题在于,它们不会一上来就露馅——它们喜欢伪装成好帖,骗我在上面耗上很久,然后突然跳出来说:「哦对了顺便一提,我其实是一篇很烂的帖子。」于是我就绝望地坐在那儿,意识到我得把所有工作推倒重来。</p><p>昨晚午夜我就是这么干的,决定改写一篇我一直想写的文章——用视觉方式展现巨大的数字,帮助我(和你)理解「千万亿 (quadrillion)」这种词到底是什么概念。</p><p>最显而易见的做法是用立方体——就是我们三年级教室里那种一立方厘米和一立方分米的木头方块,但当时已经很晚了,在绝望和神志不清的混合状态下,我做出了一个相当难以解释的怪异决定:改用酸小孩软糖作为我的计量单位。我跟你一样搞不懂这是为什么。总之结果就是我凌晨 1 点跑去 7-Eleven,盯着这面墙看了大概 70 秒:</p><p><a href="https://4.bp.blogspot.com/-zf8-BevhU9c/Uk0d1QgzW_I/AAAAAAAAFnU/HNVBC6JUbDA/s1600/1.JPG" target="_blank" rel="noreferrer"><br></a><a href="https://4.bp.blogspot.com/-zf8-BevhU9c/Uk0d1QgzW_I/AAAAAAAAFnU/HNVBC6JUbDA/s1600/1.JPG" target="_blank" rel="noreferrer"><img src="'+p+'" alt=""></a></p><p>然而,店里居然没有酸小孩软糖。</p><p>我在店里晃了一会儿,终于发现了这个东西,盯着它看了很久才确定它真的不是我想要的。</p><p><a href="https://2.bp.blogspot.com/-hWgy97JbpRk/Uk0d1-U6KuI/AAAAAAAAFnk/Pu1R0g08fBo/s1600/2.JPG" target="_blank" rel="noreferrer"><img src="'+s+'" alt=""></a></p><p>我转战附近另一家便利店。他们也没有普通版的酸小孩软糖,只有一种烦人的「eXtreme(极限版)」。我不太高兴,但夜已深,我正在变老,而且这两种看起来也够像了,于是我买了十包。</p><p><a href="https://3.bp.blogspot.com/-5U1-FLLDjUY/Uk0d2noO-SI/AAAAAAAAFnw/8cm-4uvq6ds/s1600/3.JPG" target="_blank" rel="noreferrer"><img src="'+i+'" alt=""></a></p><p>我无法想象在凌晨 1:30 目睹这次购物的收银员心里是怎么想的,除了「这家伙即将开一场史上最凄凉的单人派对」以外。</p><p>我终于回到家,拆开袋子,开始丈量。</p><p><a href="https://2.bp.blogspot.com/-PzI6p52fkIs/Uk0d2w9QYKI/AAAAAAAAFn4/Ins3eKj1-n0/s1600/5.JPG" target="_blank" rel="noreferrer"><img src="'+l+'" alt=""></a></p><p><a href="https://3.bp.blogspot.com/-OGnHndY9CsE/Uk0d2y48e0I/AAAAAAAAFn8/1ueL7IRMtkw/s1600/6.JPG" target="_blank" rel="noreferrer"><img src="'+n+'" alt=""></a></p><p><a href="https://2.bp.blogspot.com/-Lgl9CrJ0L7o/Uk0d3I39UCI/AAAAAAAAFoA/6aLGHGlsveA/s1600/7.JPG" target="_blank" rel="noreferrer"><img src="'+h+'" alt=""></a></p><p>3厘米 x 1厘米 x 0.5厘米。</p><p>接下来我排了10个。请注意吉百利 (Cadbury) 为它家 eXtreme 版酸糖小孩 (Sour Patch Kids) 挑选的那种毫无食欲、堪比放射性废料的颜色:</p><p><a href="https://3.bp.blogspot.com/-RC8TUrxOSOs/Uk0d1uQKirI/AAAAAAAAFn0/rJ3_HxPzKhg/s1600/10.JPG" target="_blank" rel="noreferrer"><img src="'+A+'" alt=""></a></p><p>然后我摆了50个:</p><p><a href="https://4.bp.blogspot.com/-faz7NzNJ8TY/Uk0d1F6_AXI/AAAAAAAAFnM/1uzClA1xvkw/s1600/11.JPG" target="_blank" rel="noreferrer"><img src="'+g+'" alt=""></a></p><p>再在上面加一层50个,凑成100个:</p><p><a href="https://4.bp.blogspot.com/-wdj0R-6v3LM/Uk0fKCWQZTI/AAAAAAAAFoM/FNV5S_smJ8M/s1600/100.png" target="_blank" rel="noreferrer"><img src="'+d+'" alt=""></a></p><p>在那个充满自我厌恶时刻的夜晚里,凌晨2点独自一人小心翼翼地把50颗 eXtreme 酸糖小孩摞在另外50颗 eXtreme 酸糖小孩上面,是全程最低谷。往下说——</p><p>谢天谢地,后面的搭建我都可以复制粘贴了。下一步是把上面那个100颗的结构堆10个,凑出1,000颗:</p><p><a href="https://2.bp.blogspot.com/-LQRpFt6gZEE/Uk0fJj_fvFI/AAAAAAAAFoU/VVRNJaXXyZM/s1600/1k.png" target="_blank" rel="noreferrer"><img src="'+c+'" alt=""></a></p><p>那个盒子是10厘米 x 10厘米 x 15厘米,所以100万颗酸糖小孩就是一个1米 x 1米 x 1.5米的盒子:</p><p><a href="https://2.bp.blogspot.com/-XjmQbp6FxXo/Uk3izPcwz0I/AAAAAAAAFp0/INV0oeEsBq0/s1600/1m.png" target="_blank" rel="noreferrer"><img src="'+m+'" alt=""></a></p><p>把<em>那种</em>盒子来1,000个,就得到一个10米 x 10米 x 15米、装着10亿颗酸糖小孩的盒子。比波士顿芬威球场那面绿怪墙 (Green Monster) 顶部略矮一点点:</p><p><a href="https://4.bp.blogspot.com/-ptO3MKDhgwM/Uk0fKKUpCEI/AAAAAAAAFoc/6MiQXXZCCKo/s1600/1b.png" target="_blank" rel="noreferrer"><img src="'+u+'" alt=""></a></p><p>再来1,000个那种盒子,我们就达到了1万亿颗酸糖小孩,形成一个100米 x 100米 x 150米的盒子,顺手压死中央公园一堆松鼠:</p><p><a href="https://2.bp.blogspot.com/-fWeTPlDsceg/Uk0fNl3mL6I/AAAAAAAAFpk/nXQHkjfTT2M/s1600/1t.png" target="_blank" rel="noreferrer"><img src="'+k+'" alt=""></a></p><p>这有助于说明1万亿是多么庞大的一个数字。1万亿很重要,因为它是日常生活中会碰到的最大的数字。我们碰到万亿这个量级主要是跟政府和金钱有关,这数字大到什么程度呢——把1万亿颗酸糖小孩紧紧压实堆起来,能覆盖一整个橄榄球场,而且高得像一栋30层的大楼。</p><p>现在我们进入的是一般人根本无法在脑子里成像的数字领域。所幸,我们还有我这套弱智的酸糖小孩方法帮忙。</p><p>把上面那个足球场大小的万亿盒子拿1,000个来,以10 x 10 x 10的方式排成一个1公里 x 1公里 x 1.5公里的大盒子,我们现在就有了1千万亿 (quadrillion) 颗酸糖小孩,覆盖了曼哈顿下城的大部分。1千万亿就是一千个万亿,或者一百万个十亿,写出来是 1,000,000,000,000,000。</p><p>作为参照,我把帝国大厦和世界第一高楼——迪拜的哈利法塔放在了盒子旁边。</p><p><a href="https://2.bp.blogspot.com/-azwX4SUz4ME/Uk0fLl_S67I/AAAAAAAAFo4/1Tr5hUrln-s/s1600/1qd.png" target="_blank" rel="noreferrer"><img src="'+_+'" alt=""></a></p><p>顺便说一下,专家估计地球上的蚂蚁数量在 1 到 10 千万亿只之间。</p><p>下一步是 100 亿亿(quintillion)。商用航班在最高巡航高度时,飞行高度<em>刚好</em>超过这个 10 公里 x 10 公里 x 15 公里的盒子的顶部,这个盒子覆盖了洛杉矶西区的大部分地区:</p><p><a href="https://1.bp.blogspot.com/-_1NraKkbvqo/Uk0fMmVRP8I/AAAAAAAAFpM/vpjmn41aF3A/s1600/1qnt.png" target="_blank" rel="noreferrer"><img src="'+b+'" alt=""></a></p><p>想知道一个原子有多小?根据 <a href="http://www.physlink.com/education/askexperts/ae342.cfm" target="_blank" rel="noreferrer">Physlink.com</a>,一粒盐里有 1.2 百亿亿个原子。所以想想上面这个飞机高度、密实堆叠的酸味小孩糖巨型堆。<em>一粒盐里的</em>原子数比这还多。更震撼的是,<a href="http://www.npr.org/blogs/krulwich/2012/09/17/161096233/which-is-greater-the-number-of-sand-grains-on-earth-or-stars-in-the-sky" target="_blank" rel="noreferrer">NPR 表示</a>,全世界的沙粒数量大约是 7.5 百亿亿,仅仅是一粒盐里原子数量的 7 倍左右。此外,1.7 百亿亿代表着你要用酸味小孩糖铺满整个地球表面所需要的数量。我在下面画了 1.7 百亿亿——所以如果你把这个盒子摊平成一层,它会完整覆盖地球的每一寸表面:</p><p><a href="https://4.bp.blogspot.com/-xYASAUhMZwg/Uk0fNTUkwsI/AAAAAAAAFpg/tCJ4Y3U6f0c/s1600/cover+world.png" target="_blank" rel="noreferrer"><img src="'+f+'" alt=""></a></p><p>1000 个百亿亿的盒子加起来是 1 千亿亿(sextillion),也就是我们上面看到的那种放在中央公园的万亿盒子的 10 亿倍。1 千亿亿颗酸味小孩糖能堆成一个 100 公里 x 100 公里 x 150 公里的堆,能盖住整个瑞士。注意图中那架飞机代表的是商用飞机的最高飞行高度:</p><p><a href="https://4.bp.blogspot.com/-y59WWSXNVRw/Uk0fM_TWR4I/AAAAAAAAFpU/XbaV09IWC40/s1600/1sx.png" target="_blank" rel="noreferrer"><img src="'+w+'" alt=""></a></p><p>1000 个千亿亿等于 1 万亿亿(septillion),而一万亿亿颗酸味小孩糖(1000 公里 x 1000 公里 x 1500 公里)能盖住印度大部分地区,并向太空深处延伸,超过国际空间站:</p><p><a href="https://3.bp.blogspot.com/-bPCApVBA0aE/Uk0fMaf4loI/AAAAAAAAFpQ/myyyaTpkx-M/s1600/1sp.png" target="_blank" rel="noreferrer"><img src="'+q+'" alt=""></a></p><p>还记得化学课上的阿伏伽德罗常数 (Avogadro&#39;s Number) 吗?它是 1 克氢中氢分子的数量,也是 1 摩尔物质中的原子数。这个数是 6.022e23,也就是 0.6 万亿亿,相当于上面那个盒子的 60%。阿伏伽德罗本人<a href="https://upload.wikimedia.org/wikipedia/commons/3/3d/Avogadro_Amedeo.jpg" target="_blank" rel="noreferrer">长得不咋样</a>。</p><p>1000 秭 (septillion) 就是 1 穰 (octillion),到这个数量级,已经超出了所有相关参照物。1 穰颗酸酸小人糖 (Sour Patch Kids) 差不多和地球一样大:</p><p><a href="https://1.bp.blogspot.com/-9jhcOEwbtjs/Uk0fLk2jAHI/AAAAAAAAFo8/un8vFScChj8/s1600/1o.png" target="_blank" rel="noreferrer"><img src="'+U+'" alt=""></a></p><p>1000 个地球大小的穰级盒子等于 1 沟 (nonillion),也就是 1,000,000,000,000,000,000,000,000,000,000 颗酸酸小人糖。它延伸的距离大约是地球到月球距离 (384,400 公里) 的一半,图中地球和月球都是按比例绘制的:</p><p><a href="https://1.bp.blogspot.com/-NCVbnuJHUxA/Uk0fK_5Q-_I/AAAAAAAAFos/wdwhF9z8-B4/s1600/1n.png" target="_blank" rel="noreferrer"><img src="'+P+'" alt=""></a></p><p>我<em>浑身颤抖</em>地想继续下去。我需要知道下一个 (涧,decillion) 和太阳比起来有多大,再下一个和整个太阳系比起来有多大,还要经过多少个「-illion」才能超过整个银河系。但我在集中意志力,准备停下来。因为这篇文章讲的是大数字,不是关于宇宙和距离的——相信我,以后会有一篇<em>详尽</em>的关于宇宙和距离的文章,毕竟我从三岁起就在跟天文学认真谈恋爱了。</p><p>P.S. 酸酸小人糖质量很差。没什么能像打开十包糖然后盯着一堆看上一阵子那样,把某样东西「用最廉价的方式在工厂里被制造出来」的事实暴露得如此彻底。</p><h2 id="p-p-s-尽管在我搭建「100」结构的过程中越来越对它们感到反胃-整个晚上我还是至少吃掉了-30-颗。" tabindex="-1">P.P.S. 尽管在我搭建「100」结构的过程中越来越对它们感到反胃,整个晚上我还是至少吃掉了 30 颗。 <a class="header-anchor" href="#p-p-s-尽管在我搭建「100」结构的过程中越来越对它们感到反胃-整个晚上我还是至少吃掉了-30-颗。" aria-label="Permalink to &quot;P.P.S. 尽管在我搭建「100」结构的过程中越来越对它们感到反胃,整个晚上我还是至少吃掉了 30 颗。&quot;">​</a></h2><p>如果你喜欢 Wait But Why,请注册我们的 <strong><a href="https://newsletter.waitbutwhy.com/join" target="_blank" rel="noreferrer">邮件列表</a></strong>,新文章发布时我们会发给你。</p><p>想支持 Wait But Why,请访问我们的 <strong><a href="https://patreon.com/waitbutwhy" target="_blank" rel="noreferrer">Patreon 页面</a></strong>。</p><p><strong>______</strong></p><p><strong>关于令人抓狂的大数字的另外两篇 Wait But Why 文章:</strong></p><p><a href="https://waitbutwhy.com/2014/11/from-1-to-1000000.html" target="_blank" rel="noreferrer">从 1 到 1,000,000</a></p><p><a href="https://waitbutwhy.com/2014/11/1000000-grahams-number.html" target="_blank" rel="noreferrer">从 1,000,000 到葛立恒数</a></p><p><strong>以及另外三篇「无意义计算」系列文章:</strong></p><p><a href="https://waitbutwhy.com/2015/03/7-3-billion-people-one-building.html" target="_blank" rel="noreferrer">把所有人类塞进一栋楼里</a></p><p><a href="https://waitbutwhy.com/2014/03/combined-wealth-world.html" target="_blank" rel="noreferrer">把全世界的财富压成一个金立方体</a></p><p><a href="https://waitbutwhy.com/2013/09/putting-all-worlds-water-into-big-cube.html" target="_blank" rel="noreferrer">把全世界的水装进立方容器里</a></p><p><a href="https://twitter.com/share" target="_blank" rel="noreferrer">Tweet</a></p><p><a href="//www.pinterest.com/pin/create/button/?url=https://waitbutwhy.com/2013/10/what-does-quadrillion-sour-patch-kids.html&amp;description=What%20Does%20a%20Quadrillion%20Sour%20Patch%20Kids%20Look%20Like?" target="_blank" rel="noreferrer"><img src="'+x+'" alt=""></a></p>',69)])])}const C=t(F,[["render",I]]);export{L as __pageData,C as default};
